import { db } from '../db';
import { bills } from '../../shared/schemas/financial';
import { users } from '../../shared/schema';
import { eq, and, gte, isNull, or } from 'drizzle-orm';
import { v4 as uuidv4 } from 'uuid';
import type { Bill } from '../../shared/schema';

/**
 * Advanced Bill Auto-Generation Service.
 *
 * Handles the sophisticated bill management system including:
 * - Auto-generation for recurrent bills based on payment schedules
 * - Creating future bill instances with pre-populated data
 * - Multiple payment plans and custom schedules
 * - Auto-generated labels and template relationships
 * - Next year bill generation for easy management.
 */
export class BillAutoGenerationService {
  
  /**
   * Generate bills for the next year based on a recurrent source bill with enhanced rules.
   * @param sourceBill - The recurrent bill to use as a template
   * @returns Array of generated bills for next year
   */
  generateForNextYear(sourceBill: Bill): Bill[] {
    // Enhanced auto-generation rules
    if (!this.canGenerateFromBill(sourceBill)) {
      throw new Error(`Bill ${sourceBill.id} does not meet auto-generation criteria`);
    }

    const nextYear = new Date().getFullYear() + 1;
    const startDate = new Date(nextYear, 0, 1); // January 1st of next year
    const endDate = new Date(nextYear, 11, 31); // December 31st of next year

    const dueDates = this.calculateNextDueDates(sourceBill.schedulePayment || 'yearly', startDate, endDate, sourceBill.scheduleCustom);
    
    return dueDates.map((dueDate, index) => ({
      id: '', // Will be generated on insert
      buildingId: sourceBill.buildingId,
      billNumber: this.generateAdvancedBillNumber(sourceBill, dueDate, index),
      title: sourceBill.title,
      description: sourceBill.description,
      category: sourceBill.category,
      vendor: sourceBill.vendor,
      paymentType: 'unique' as const, // Generated bills are unique
      schedulePayment: null,
      scheduleCustom: null,
      costs: sourceBill.costs,
      totalAmount: sourceBill.totalAmount,
      startDate: dueDate.toISOString().split('T')[0],
      endDate: this.calculateEndDate(sourceBill, dueDate),
      status: 'draft' as const,
      filePath: null,
      fileName: null,
      fileSize: null,
      isAiAnalyzed: false,
      aiAnalysisData: null,
      notes: `Auto-generated from recurrent bill: ${sourceBill.title} (${sourceBill.billNumber})`,
      isAutoGenerated: true,
      sourceTemplateId: sourceBill.id,
      autoGeneratedLabel: this.createAdvancedAutoGeneratedLabel(sourceBill, dueDate, index),
      createdBy: sourceBill.createdBy,
      createdAt: new Date(),
      updatedAt: new Date(),
    })) as Bill[];
  }

  /**
   * Enhanced rules to determine if a bill can generate auto-bills.
   * @param bill
   */
  private canGenerateFromBill(bill: Bill): boolean {
    // Rule 1: Must be recurrent
    if (bill.paymentType !== 'recurrent') {
      return false;
    }

    // Rule 2: Must have valid schedule
    if (!bill.schedulePayment) {
      return false;
    }

    // Rule 3: Must not be cancelled or overdue
    if (['cancelled', 'overdue'].includes(bill.status)) {
      return false;
    }

    // Rule 4: Must have valid amount
    if (!bill.totalAmount || parseFloat(bill.totalAmount) <= 0) {
      return false;
    }

    // Rule 5: Custom schedules must have valid dates
    if (bill.schedulePayment === 'custom') {
      if (!bill.scheduleCustom || !this.validateCustomSchedule(bill.scheduleCustom)) {
        return false;
      }
    }

    // Rule 6: Must not be an auto-generated bill itself
    if (bill.isAutoGenerated) {
      return false;
    }

    return true;
  }

  /**
   * Generate advanced bill number with smart formatting.
   * @param sourceBill
   * @param dueDate
   * @param index
   */
  private generateAdvancedBillNumber(sourceBill: Bill, dueDate: Date, index: number): string {
    const year = dueDate.getFullYear();
    const month = String(dueDate.getMonth() + 1).padStart(2, '0');
    const sequence = String(index + 1).padStart(2, '0');
    
    // Format: ORIGINAL-YYYY-MM-SEQ
    return `${sourceBill.billNumber}-${year}-${month}-${sequence}`;
  }

  /**
   * Calculate appropriate end date for auto-generated bill.
   * @param sourceBill
   * @param startDate
   */
  private calculateEndDate(sourceBill: Bill, startDate: Date): string | null {
    if (!sourceBill.endDate) {
      return null;
    }

    // For recurring bills, calculate relative end date
    const originalStart = new Date(sourceBill.startDate);
    const originalEnd = new Date(sourceBill.endDate);
    const daysDifference = Math.floor((originalEnd.getTime() - originalStart.getTime()) / (1000 * 60 * 60 * 24));
    
    const newEndDate = new Date(startDate);
    newEndDate.setDate(newEndDate.getDate() + daysDifference);
    
    return newEndDate.toISOString().split('T')[0];
  }

  /**
   * Create advanced auto-generated label with context.
   * @param sourceBill
   * @param dueDate
   * @param index
   */
  private createAdvancedAutoGeneratedLabel(sourceBill: Bill, dueDate: Date, index: number): string {
    const monthYear = dueDate.toLocaleDateString('en-US', { month: 'short', year: 'numeric' });
    const schedule = sourceBill.schedulePayment;
    
    let scheduleLabel = '';
    switch (schedule) {
      case 'monthly':
        scheduleLabel = 'Monthly';
        break;
      case 'quarterly':
        const quarter = Math.floor(dueDate.getMonth() / 3) + 1;
        scheduleLabel = `Q${quarter}`;
        break;
      case 'yearly':
        scheduleLabel = 'Annual';
        break;
      case 'weekly':
        const week = Math.ceil(dueDate.getDate() / 7);
        scheduleLabel = `Week ${week}`;
        break;
      default:
        scheduleLabel = 'Auto';
    }
    
    return `Auto: ${sourceBill.title} - ${scheduleLabel} ${monthYear}`;
  }

  /**
   * Calculate next due dates based on payment schedule.
   * @param schedule - Payment schedule type
   * @param startDate - Start date for calculations
   * @param endDate - End date limit
   * @param customDates - Custom dates array if schedule is 'custom'
   * @returns Array of due dates
   */
  calculateNextDueDates(schedule: string, startDate?: Date, endDate?: Date, customDates?: string[]): Date[] {
    const start = startDate || new Date();
    const end = endDate || new Date(start.getFullYear() + 1, 11, 31);
    
    if (schedule === 'custom' && customDates) {
      return this.calculateCustomOccurrences(start, end, customDates);
    }
    
    return this.calculateOccurrences(start, end, schedule);
  }

  /**
   * Create auto-generated label for bills.
   * @param sourceBill - Source bill template
   * @param year - Year for the generated bill
   * @returns Formatted label
   */
  createAutoGeneratedLabel(sourceBill: Bill, year: number): string {
    return `Auto: ${sourceBill.title} ${year}`;
  }

  /**
   * Validate custom schedule dates.
   * @param customDates - Array of custom date strings
   * @returns True if valid, false otherwise
   */
  validateCustomSchedule(customDates: string[]): boolean {
    if (!customDates || customDates.length === 0) {
      return false;
    }

    return customDates.every(dateStr => {
      const date = new Date(dateStr);
      return date instanceof Date && !isNaN(date.getTime());
    });
  }
  /**
   * Get bills by reference (auto-generated bills linked to a parent).
   * @param parentBillId
   */
  private async getBillsByReference(parentBillId: string): Promise<Bill[]> {
    try {
      const existingBills = await db.select().from(bills).where(eq(bills.sourceTemplateId, parentBillId));

      return existingBills as Bill[];
    } catch (error: any) {
      console.error('❌ Error getting bills by reference:', error);
      return [];
    }
  }

  /**
   * Set end date for a recurrent bill (stops future auto-generation).
   * @param billId
   * @param endDate
   */
  async setRecurrenceEndDate(billId: string, endDate: Date): Promise<void> {
    try {
      await db
        .update(bills)
        .set({
          endDate: endDate.toISOString().split('T')[0],
          updatedAt: new Date(),
        })
        .where(eq(bills.id, billId));
    } catch (error: any) {
      console.error('❌ Error setting recurrence end date:', error);
      throw error;
    }
  }

  /**
   * Generate future bill instances for a recurrent bill up to 3 years.
   * Creates actual bill records that users can interact with individually.
   * @param parentBill
   */
  async generateFutureBillInstances(parentBill: Bill): Promise<{
    billsCreated: number;
    generatedUntil: string;
  }> {
    if (parentBill.paymentType !== 'recurrent') {
      throw new Error('Only recurrent bills can generate future instances');
    }


    // Calculate projection period - respect endDate if set
    const startDate = new Date(parentBill.startDate);
    startDate.setFullYear(startDate.getFullYear() + 1); // Start from next year

    let endDate: Date;
    if (parentBill.endDate) {
      endDate = new Date(parentBill.endDate);
    } else {
      endDate = new Date();
      endDate.setFullYear(endDate.getFullYear() + 3); // 3 years from now
    }

    // Check if there are already auto-generated bills to avoid duplicates
    const existingBills = await this.getBillsByReference(parentBill.id);
    if (existingBills.length > 0) {
      console.log(
        `⚠️ Found ${existingBills.length} existing auto-generated bills, skipping generation`
      );
      return {
        billsCreated: 0,
        generatedUntil: endDate.toISOString().split('T')[0],
      };
    }

    const generatedBills: unknown[] = [];
    const currentDate = new Date(startDate);
    let billsCreated = 0;

    // Calculate occurrences based on schedule (auto-detect from parent bill)
    const scheduleType = this.detectScheduleType(parentBill);
    const occurrences = this.calculateOccurrences(currentDate, endDate, scheduleType);

    for (const occurrenceDate of occurrences) {
      // Handle multiple payment plans
      const paymentParts = this.calculatePaymentParts(parentBill, occurrenceDate);

      for (let partIndex = 0; partIndex < paymentParts.length; partIndex++) {
        const paymentPart = paymentParts[partIndex];

        const generatedBill = {
          id: uuidv4(),
          buildingId: parentBill.buildingId,
          billNumber: this.generateBillNumber(parentBill, occurrenceDate, partIndex),
          title: this.generateBillTitle(parentBill, occurrenceDate, partIndex, paymentParts.length),
          description: `Auto-generated from: ${parentBill.title}`,
          category: parentBill.category,
          vendor: parentBill.vendor || 'Auto-Generated',
          paymentType: 'unique' as const, // Generated bills are unique payments
          schedulePayment: 'unique' as const,
          costs: [paymentPart.amount.toString()],
          totalAmount: paymentPart.amount.toString(),
          startDate: paymentPart.dueDate.toISOString().split('T')[0],
          endDate: null,
          status: 'draft' as const,
          documentPath: null,
          documentName: null,
          isAiAnalyzed: false,
          aiAnalysisData: null,
          notes: `Auto-generated from: ${parentBill.title} (Bill #${parentBill.billNumber}). Generated as part ${partIndex + 1}/${paymentParts.length} for ${occurrenceDate.toLocaleDateString()}.`,
          isAutoGenerated: true,
          sourceTemplateId: parentBill.id,
          autoGeneratedLabel: this.createAutoGeneratedLabel(parentBill, occurrenceDate.getFullYear()),
          createdBy: parentBill.createdBy,
          createdAt: new Date(),
          updatedAt: new Date(),
        };

        generatedBills.push(generatedBill);
        billsCreated++;

        // Batch insert every 100 bills for performance
        if (generatedBills.length >= 100) {
          await this.insertBillsBatch(generatedBills);
          generatedBills.length = 0;
        }
      }
    }

    // Insert remaining bills
    if (generatedBills.length > 0) {
      await this.insertBillsBatch(generatedBills);
    }


    return {
      billsCreated,
      generatedUntil: endDate.toISOString().split('T')[0],
    };
  }

  /**
   * Handle multiple payment logic for bills.
   * Examples:
   * - 60% now, 40% in 2 months
   * - 12 monthly payments of equal amounts
   * - Quarterly payments with varying amounts.
   * @param parentBill
   * @param occurrenceDate
   */
  private calculatePaymentParts(
    parentBill: Bill,
    occurrenceDate: Date
  ): Array<{
    amount: number;
    dueDate: Date;
    partNumber: number;
  }> {
    const costs = parentBill.costs.map((cost) => parseFloat(cost));
    const paymentParts: Array<{ amount: number; dueDate: Date; partNumber: number }> = [];

    if (costs.length === 1) {
      // Single payment
      paymentParts.push({
        amount: costs[0],
        dueDate: new Date(occurrenceDate),
        partNumber: 1,
      });
    } else {
      // Multiple payments - create payment schedule
      costs.forEach((amount, _index) => {
        const dueDate = new Date(occurrenceDate);

        // For multiple costs, spread payments over time
        // First payment on occurrence date, subsequent payments monthly
        dueDate.setMonth(dueDate.getMonth() + _index);

        paymentParts.push({
          amount,
          dueDate,
          partNumber: _index + 1,
        });
      });
    }

    return paymentParts;
  }

  /**
   * Detect schedule type from parent bill characteristics.
   * @param parentBill
   */
  private detectScheduleType(parentBill: Bill): string {
    const costs = parentBill.costs || [];

    // Auto-detect based on cost array length and bill patterns
    if (costs.length === 12) {
      return 'monthly'; // 12 payments = monthly
    } else if (costs.length === 4) {
      return 'quarterly'; // 4 payments = quarterly
    } else if (costs.length === 2) {
      return 'yearly'; // 2 payments = bi-annual, treat as yearly with split
    } else if (costs.length === 1) {
      // Single payment - determine frequency from title/description
      const title = parentBill.title.toLowerCase();
      if (title.includes('annual') || title.includes('yearly')) {
        return 'yearly';
      } else if (title.includes('quarterly')) {
        return 'quarterly';
      } else if (title.includes('monthly')) {
        return 'monthly';
      } else {
        return 'yearly'; // Default to yearly
      }
    }

    return 'yearly'; // Default fallback
  }

  /**
   * Calculate all occurrence dates based on schedule type.
   * @param startDate
   * @param endDate
   * @param scheduleType
   */
  /**
   * Calculate occurrences based on payment schedule with advanced edge case handling.
   * Handles leap years, month-end dates, holidays, and complex patterns.
   * @param startDate
   * @param endDate
   * @param scheduleType
   */
  private calculateOccurrences(startDate: Date, endDate: Date, scheduleType: string): Date[] {
    const occurrences: Date[] = [];
    let currentDate = new Date(startDate);
    const originalDay = startDate.getDate();

    // Standard schedule types with enhanced date handling
    while (currentDate <= endDate) {
      occurrences.push(new Date(currentDate));

      switch (scheduleType) {
        case 'weekly':
          currentDate = this.addWeeks(currentDate, 1);
          break;
        case 'monthly':
          currentDate = this.addMonthsWithDayPreservation(currentDate, 1, originalDay);
          break;
        case 'quarterly':
          currentDate = this.addMonthsWithDayPreservation(currentDate, 3, originalDay);
          break;
        case 'yearly':
          currentDate = this.addYearsWithDayPreservation(currentDate, 1, originalDay);
          break;
        default:
          throw new Error(`Unknown schedule type: ${scheduleType}`);
      }

      // Safety check to prevent infinite loops
      if (occurrences.length > 10000) {
        break;
      }
    }

    // Apply business day adjustments to all occurrences
    return occurrences.map(date => this.adjustForBusinessDay(date));
  }

  /**
   * Add weeks to a date safely.
   * @param date
   * @param weeks
   */
  private addWeeks(date: Date, weeks: number): Date {
    const result = new Date(date);
    result.setDate(result.getDate() + (weeks * 7));
    return result;
  }

  /**
   * Add months while preserving the original day, handling month-end edge cases.
   * @param date
   * @param months
   * @param originalDay
   */
  private addMonthsWithDayPreservation(date: Date, months: number, originalDay: number): Date {
    const result = new Date(date);
    result.setMonth(result.getMonth() + months);
    
    // Handle month-end dates (e.g., January 31st -> February 28th)
    const lastDayOfMonth = new Date(result.getFullYear(), result.getMonth() + 1, 0).getDate();
    const targetDay = Math.min(originalDay, lastDayOfMonth);
    
    result.setDate(targetDay);
    return result;
  }

  /**
   * Add years while preserving the original day, handling leap year edge cases.
   * @param date
   * @param years
   * @param originalDay
   */
  private addYearsWithDayPreservation(date: Date, years: number, originalDay: number): Date {
    const result = new Date(date);
    result.setFullYear(result.getFullYear() + years);
    
    // Handle February 29th on non-leap years
    if (originalDay === 29 && result.getMonth() === 1 && !this.isLeapYear(result.getFullYear())) {
      result.setDate(28); // February 28th instead of 29th
    } else {
      const lastDayOfMonth = new Date(result.getFullYear(), result.getMonth() + 1, 0).getDate();
      const targetDay = Math.min(originalDay, lastDayOfMonth);
      result.setDate(targetDay);
    }
    
    return result;
  }

  /**
   * Check if a year is a leap year.
   * @param year
   */
  private isLeapYear(year: number): boolean {
    return ((year % 4 === 0) && (year % 100 !== 0)) || (year % 400 === 0);
  }

  /**
   * Adjust date to next business day if it falls on weekend or holiday.
   * @param date
   */
  private adjustForBusinessDay(date: Date): Date {
    const result = new Date(date);
    
    // Skip weekends (Saturday = 6, Sunday = 0)
    while (result.getDay() === 0 || result.getDay() === 6) {
      result.setDate(result.getDate() + 1);
    }
    
    // Check for Quebec statutory holidays and adjust
    if (this.isQuebecStatutoryHoliday(result)) {
      result.setDate(result.getDate() + 1);
      // Recursively check if the next day is also a weekend/holiday
      return this.adjustForBusinessDay(result);
    }
    
    return result;
  }

  /**
   * Check if a date is a Quebec statutory holiday.
   * @param date
   */
  private isQuebecStatutoryHoliday(date: Date): boolean {
    const month = date.getMonth() + 1; // 1-based month
    const day = date.getDate();
    const year = date.getFullYear();
    
    // Fixed Quebec holidays
    const fixedHolidays = [
      { month: 1, day: 1 },   // New Year's Day
      { month: 6, day: 24 },  // Saint-Jean-Baptiste Day
      { month: 7, day: 1 },   // Canada Day
      { month: 12, day: 25 }, // Christmas Day
    ];

    // Check fixed holidays
    for (const holiday of fixedHolidays) {
      if (month === holiday.month && day === holiday.day) {
        return true;
      }
    }

    // Variable holidays (Easter-based, Victoria Day, etc.)
    const easter = this.calculateEaster(year);
    const goodFriday = new Date(easter);
    goodFriday.setDate(easter.getDate() - 2);
    
    const easterMonday = new Date(easter);
    easterMonday.setDate(easter.getDate() + 1);
    
    // Victoria Day (Monday preceding May 25)
    const victoriaDay = this.getVictoriaDay(year);
    
    const variableHolidays = [goodFriday, easterMonday, victoriaDay];
    
    for (const holiday of variableHolidays) {
      if (date.toDateString() === holiday.toDateString()) {
        return true;
      }
    }
    
    return false;
  }

  /**
   * Calculate Easter Sunday for a given year.
   * @param year
   */
  private calculateEaster(year: number): Date {
    const a = year % 19;
    const b = Math.floor(year / 100);
    const c = year % 100;
    const d = Math.floor(b / 4);
    const e = b % 4;
    const f = Math.floor((b + 8) / 25);
    const g = Math.floor((b - f + 1) / 3);
    const h = (19 * a + b - d - g + 15) % 30;
    const i = Math.floor(c / 4);
    const k = c % 4;
    const l = (32 + 2 * e + 2 * i - h - k) % 7;
    const m = Math.floor((a + 11 * h + 22 * l) / 451);
    const month = Math.floor((h + l - 7 * m + 114) / 31);
    const day = ((h + l - 7 * m + 114) % 31) + 1;
    
    return new Date(year, month - 1, day);
  }

  /**
   * Get Victoria Day (Monday preceding May 25).
   * @param year
   */
  private getVictoriaDay(year: number): Date {
    const may25 = new Date(year, 4, 25); // May 25
    const dayOfWeek = may25.getDay();
    const daysToSubtract = dayOfWeek === 0 ? 6 : dayOfWeek - 1; // Get preceding Monday
    
    const victoriaDay = new Date(may25);
    victoriaDay.setDate(25 - daysToSubtract);
    
    return victoriaDay;
  }

  /**
   * Handle custom recurring dates (yearly repetition).
   * @param startDate
   * @param endDate
   * @param customDates
   */
  private calculateCustomOccurrences(
    startDate: Date,
    endDate: Date,
    customDates: string[]
  ): Date[] {
    const occurrences: Date[] = [];
    const startYear = startDate.getFullYear();
    const endYear = endDate.getFullYear();

    for (let year = startYear; year <= endYear; year++) {
      for (const dateStr of customDates) {
        const customDate = new Date(dateStr);
        customDate.setFullYear(year);

        if (customDate >= startDate && customDate <= endDate) {
          occurrences.push(new Date(customDate));
        }
      }
    }

    return occurrences.sort((a, b) => a.getTime() - b.getTime());
  }

  /**
   * Generate unique bill number for auto-generated bills.
   * @param parentBill
   * @param occurrenceDate
   * @param partIndex
   */
  private generateBillNumber(parentBill: Bill, occurrenceDate: Date, partIndex: number): string {
    const dateStr = occurrenceDate.toISOString().slice(0, 7); // YYYY-MM
    const partSuffix = partIndex > 0 ? `-P${partIndex + 1}` : '';
    return `${parentBill.billNumber}-${dateStr}${partSuffix}`;
  }

  /**
   * Generate descriptive title for auto-generated bills.
   * @param parentBill
   * @param occurrenceDate
   * @param partIndex
   * @param totalParts
   */
  private generateBillTitle(
    parentBill: Bill,
    occurrenceDate: Date,
    partIndex: number,
    totalParts: number
  ): string {
    const monthYear = occurrenceDate.toLocaleDateString('en-US', {
      month: 'long',
      year: 'numeric',
    });

    if (totalParts > 1) {
      return `${parentBill.title} ${monthYear} (Auto-Generated)`;
    } else {
      return `${parentBill.title} ${monthYear} (Auto-Generated)`;
    }
  }

  /**
   * Clean up existing auto-generated bills for a parent bill.
   * @param parentBillId
   */
  private async cleanupExistingGeneratedBills(parentBillId: string): Promise<void> {
    try {
      const result = await db
        .delete(bills)
        .where(
          and(
            eq(bills.sourceTemplateId, parentBillId),
            eq(bills.isAutoGenerated, true),
            or(eq(bills.status, 'draft'), eq(bills.status, 'sent'))
          )
        );
      console.log(`🗑️ Cleaned up auto-generated bills for parent bill ${parentBillId}`);
    } catch (error: any) {
      console.error('❌ Error cleaning up generated bills:', error);
      throw error;
    }
  }

  /**
   * Batch insert bills for performance.
   * @param billBatch
   */
  private async insertBillsBatch(billBatch: any[]): Promise<void> {
    try {
      await db.insert(bills).values(billBatch);
      console.log(`✅ Batch inserted ${billBatch.length} bills`);
    } catch (error: any) {
      console.error('❌ Error inserting bill batch:', error);
      throw error;
    }
  }

  /**
   * Update all future auto-generated bills when the parent bill is modified.
   * @param parentBillId
   * @param updates
   */
  async updateGeneratedBillsFromParent(
    parentBillId: string,
    updates: Partial<Bill>
  ): Promise<{
    billsUpdated: number;
  }> {

    // Find all auto-generated bills for this parent
    const generatedBills = await db
      .select()
      .from(bills)
      .where(and(eq(bills.sourceTemplateId, parentBillId), eq(bills.isAutoGenerated, true)));

    let billsUpdated = 0;

    for (const generatedBill of generatedBills) {
      const updatedFields: Partial<Bill> = {};

      // Update fields that should propagate to generated bills
      if (updates.title) {
        // Preserve the date and part information in the title
        const titleParts = generatedBill.title.split(' - ');
        if (titleParts.length >= 2) {
          updatedFields.title = `${updates.title} - ${titleParts.slice(1).join(' - ')}`;
        }
      }

      if (updates.category) {
        updatedFields.category = updates.category;
      }
      if (updates.vendor) {
        updatedFields.vendor = updates.vendor;
      }
      if (updates.notes) {
        updatedFields.notes = `Auto-generated bill - ${updates.notes}`;
      }

      if (Object.keys(updatedFields).length > 0) {
        updatedFields.updatedAt = new Date();

        await db.update(bills).set(updatedFields).where(eq(bills.id, generatedBill.id));

        billsUpdated++;
      }
    }


    return { billsUpdated };
  }

  /**
   * Delete future auto-generated bills with cascade options.
   * @param parentBillId
   * @param deleteAllFuture
   */
  async deleteGeneratedBills(
    parentBillId: string,
    deleteAllFuture: boolean = false
  ): Promise<{
    billsDeleted: number;
  }> {
    console.log(
      `🗑️ Deleting generated bills for parent ${parentBillId}, deleteAllFuture: ${deleteAllFuture}`
    );

    let whereCondition;

    if (deleteAllFuture) {
      // Delete all future auto-generated bills
      whereCondition = and(
        eq(bills.sourceTemplateId, parentBillId),
        eq(bills.isAutoGenerated, true),
        gte(bills.startDate, new Date().toISOString().split('T')[0])
      );
    } else {
      // Delete only unpaid bills (draft/sent status)
      whereCondition = and(
        eq(bills.sourceTemplateId, parentBillId),
        eq(bills.isAutoGenerated, true),
        or(eq(bills.status, 'draft'), eq(bills.status, 'sent'))
      );
    }

    const result = await db.delete(bills).where(whereCondition);

    const billsDeleted = result.rowCount || 0;

    return { billsDeleted };
  }

  /**
   * Get statistics about generated bills for a parent bill.
   * @param parentBillId
   */
  async getGeneratedBillsStats(parentBillId: string): Promise<{
    totalGenerated: number;
    paidBills: number;
    pendingBills: number;
    futureBills: number;
    totalAmount: number;
    paidAmount: number;
  }> {
    const generatedBills = await db
      .select()
      .from(bills)
      .where(and(eq(bills.sourceTemplateId, parentBillId), eq(bills.isAutoGenerated, true)));

    const today = new Date().toISOString().split('T')[0];

    const stats = {
      totalGenerated: generatedBills.length,
      paidBills: 0,
      pendingBills: 0,
      futureBills: 0,
      totalAmount: 0,
      paidAmount: 0,
    };

    for (const bill of generatedBills) {
      const billAmount = parseFloat(bill.totalAmount);
      stats.totalAmount += billAmount;

      if (bill.status === 'paid') {
        stats.paidBills++;
        stats.paidAmount += billAmount;
      } else if (bill.startDate > today) {
        stats.futureBills++;
      } else {
        stats.pendingBills++;
      }
    }

    return stats;
  }

  /**
   * Mark a bill as paid and update related tracking.
   * @param billId
   * @param paymentDate
   */
  async markBillAsPaid(billId: string, paymentDate?: Date): Promise<void> {
    const paymentReceivedDate = paymentDate || new Date();

    await db
      .update(bills)
      .set({
        status: 'paid',
        notes: `Payment confirmed on ${paymentReceivedDate.toLocaleDateString()}`,
        updatedAt: new Date(),
      })
      .where(eq(bills.id, billId));

  }

  /**
   * Get a system user for automated operations.
   */
  private async getSystemUser(): Promise<{ id: string }> {
    const systemUsers = await db
      .select({ id: users.id })
      .from(users)
      .where(eq(users.role, 'admin'))
      .limit(1);

    if (systemUsers.length === 0) {
      throw new Error('No active users found for system operations');
    }

    return systemUsers[0];
  }

  /**
   * Bulk generate bills for all buildings with recurrent bills.
   * Background processing capability for organization-wide generation.
   * @param organizationId - Optional filter by organization
   * @param buildingIds - Optional filter by specific buildings
   */
  async bulkGenerateForAllBuildings(
    organizationId?: string, 
    buildingIds?: string[]
  ): Promise<{
    processedBuildings: number;
    generatedBills: number;
    errors: string[];
  }> {
    console.log('🚀 Starting bulk bill generation process...');
    
    let processedBuildings = 0;
    let generatedBills = 0;
    const errors: string[] = [];

    try {
      // Get all buildings that need processing
      let buildingQuery = db.select().from(buildings);
      
      if (organizationId) {
        buildingQuery = buildingQuery.where(eq(buildings.organizationId, organizationId));
      }
      
      if (buildingIds && buildingIds.length > 0) {
        buildingQuery = buildingQuery.where(sql`${buildings.id} = ANY(${buildingIds})`);
      }

      const buildingsToProcess = await buildingQuery;
      console.log(`📊 Found ${buildingsToProcess.length} buildings to process`);

      for (const building of buildingsToProcess) {
        try {
          const result = await this.generateBillsForBuilding(building.id);
          processedBuildings++;
          generatedBills += result.billsGenerated;
          
          console.log(`✅ Building ${building.name}: Generated ${result.billsGenerated} bills`);
        } catch (error: any) {
          const errorMsg = `Building ${building.name} (${building.id}): ${error.message}`;
          errors.push(errorMsg);
          console.error('❌', errorMsg);
        }
      }

      console.log(`🎉 Bulk generation complete: ${processedBuildings} buildings, ${generatedBills} bills generated`);
      
      return {
        processedBuildings,
        generatedBills,
        errors
      };
      
    } catch (error: any) {
      console.error('❌ Bulk generation failed:', error);
      throw new Error(`Bulk generation failed: ${error.message}`);
    }
  }

  /**
   * Generate bills for a specific building.
   * @param buildingId
   */
  private async generateBillsForBuilding(buildingId: string): Promise<{
    billsGenerated: number;
    templates: number;
  }> {
    // Get all recurrent bills for this building
    const recurrentBills = await db
      .select()
      .from(bills)
      .where(
        and(
          eq(bills.buildingId, buildingId),
          eq(bills.paymentType, 'recurrent'),
          eq(bills.isAutoGenerated, false)
        )
      );

    let billsGenerated = 0;
    const templates = recurrentBills.length;

    for (const recurrentBill of recurrentBills) {
      try {
        // Check if bills for next year already exist
        const nextYear = new Date().getFullYear() + 1;
        const existingBills = await db
          .select()
          .from(bills)
          .where(
            and(
              eq(bills.sourceTemplateId, recurrentBill.id),
              eq(bills.isAutoGenerated, true),
              sql`EXTRACT(year FROM ${bills.startDate}::date) = ${nextYear}`
            )
          );

        if (existingBills.length > 0) {
          console.log(`⏭️ Bills for ${recurrentBill.title} already exist for ${nextYear}`);
          continue;
        }

        // Generate new bills
        if (this.canGenerateFromBill(recurrentBill as Bill)) {
          const generatedBills = this.generateForNextYear(recurrentBill as Bill);
          
          // Insert in batches
          for (const generatedBill of generatedBills) {
            await db.insert(bills).values({
              ...generatedBill,
              id: undefined,
            });
            billsGenerated++;
          }
        }
      } catch (error: any) {
        console.error(`❌ Error generating bills for template ${recurrentBill.title}:`, error);
      }
    }

    return { billsGenerated, templates };
  }

  /**
   * Scheduled job function for automatic bill generation.
   * Should be called by cron job or scheduler.
   */
  async runScheduledGeneration(): Promise<{
    success: boolean;
    summary: string;
    details: any;
  }> {
    try {
      console.log('⏰ Running scheduled bill generation job...');
      
      const startTime = Date.now();
      const result = await this.bulkGenerateForAllBuildings();
      const endTime = Date.now();
      const duration = endTime - startTime;

      const summary = `Generated ${result.generatedBills} bills for ${result.processedBuildings} buildings in ${Math.round(duration / 1000)}s`;
      
      if (result.errors.length > 0) {
        console.warn(`⚠️ Job completed with ${result.errors.length} errors`);
      }

      return {
        success: true,
        summary,
        details: {
          ...result,
          duration,
          timestamp: new Date().toISOString()
        }
      };
      
    } catch (error: any) {
      console.error('❌ Scheduled generation job failed:', error);
      
      return {
        success: false,
        summary: `Job failed: ${error.message}`,
        details: {
          error: error.message,
          timestamp: new Date().toISOString()
        }
      };
    }
  }

  /**
   * Manual trigger for immediate generation with progress tracking.
   * @param options
   */
  async triggerManualGeneration(options: {
    organizationId?: string;
    buildingIds?: string[];
    forceRegenerate?: boolean;
  } = {}): Promise<{
    jobId: string;
    status: 'started' | 'completed' | 'failed';
    result?: any;
  }> {
    const jobId = `manual-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`;
    
    try {
      console.log(`🔄 Manual generation triggered (Job ID: ${jobId})`);
      
      if (options.forceRegenerate) {
        // Clean up existing auto-generated bills if force regenerate
        await this.cleanupAutoGeneratedBills(options.organizationId, options.buildingIds);
      }
      
      const result = await this.bulkGenerateForAllBuildings(
        options.organizationId,
        options.buildingIds
      );
      
      console.log(`✅ Manual generation completed (Job ID: ${jobId})`);
      
      return {
        jobId,
        status: 'completed',
        result
      };
      
    } catch (error: any) {
      console.error(`❌ Manual generation failed (Job ID: ${jobId}):`, error);
      
      return {
        jobId,
        status: 'failed',
        result: {
          error: error.message
        }
      };
    }
  }

  /**
   * Clean up existing auto-generated bills for bulk regeneration.
   * @param organizationId
   * @param buildingIds
   */
  private async cleanupAutoGeneratedBills(
    organizationId?: string,
    buildingIds?: string[]
  ): Promise<void> {
    let deleteQuery = db
      .delete(bills)
      .where(
        and(
          eq(bills.isAutoGenerated, true),
          or(eq(bills.status, 'draft'), eq(bills.status, 'sent'))
        )
      );

    if (organizationId) {
      // Join with buildings to filter by organization
      deleteQuery = deleteQuery.where(
        sql`${bills.buildingId} IN (
          SELECT id FROM ${buildings} WHERE organization_id = ${organizationId}
        )`
      );
    }

    if (buildingIds && buildingIds.length > 0) {
      deleteQuery = deleteQuery.where(sql`${bills.buildingId} = ANY(${buildingIds})`);
    }

    await deleteQuery;
    console.log('🗑️ Cleaned up existing auto-generated bills for regeneration');
  }
}

// Export singleton instance
export const billAutoGenerationService = new BillAutoGenerationService();
